#include "biblia.h"

void Biblia::Carregar2Pedro(Biblia* b) {
    b->dados[PEDRO2].nome = wxT("2 Pedro");

    b->dados[PEDRO2].capitulos[1].versos[1] = wxT("Simão Pedro, servo e apóstolo de Jesus Cristo, aos que conosco alcançaram fé igualmente preciosa na justiça do nosso Deus e Salvador Jesus Cristo:");
    b->dados[PEDRO2].capitulos[1].versos[2] = wxT("Graça e paz vos sejam multiplicadas no pleno conhecimento de Deus e de Jesus nosso Senhor;");
    b->dados[PEDRO2].capitulos[1].versos[3] = wxT("visto como o seu divino poder nos tem dado tudo o que diz respeito à vida e à piedade, pelo pleno conhecimento daquele que nos chamou por sua própria glória e virtude;");
    b->dados[PEDRO2].capitulos[1].versos[4] = wxT("pelas quais ele nos tem dado as suas preciosas e grandíssimas promessas, para que por elas vos torneis participantes da natureza divina, havendo escapado da corrupção, que pela concupiscência há no mundo.");
    b->dados[PEDRO2].capitulos[1].versos[5] = wxT("E por isso mesmo vós, empregando toda a diligência, acrescentai à vossa fé a virtude, e à virtude a ciência,");
    b->dados[PEDRO2].capitulos[1].versos[6] = wxT("e à ciência o domínio próprio, e ao domínio próprio a perseverança, e à perseverança a piedade,");
    b->dados[PEDRO2].capitulos[1].versos[7] = wxT("e à piedade a fraternidade, e à fraternidade o amor.");
    b->dados[PEDRO2].capitulos[1].versos[8] = wxT("Porque, se em vós houver e abundarem estas coisas, elas não vos deixarão ociosos nem infrutíferos no pleno conhecimento de nosso Senhor Jesus Cristo.");
    b->dados[PEDRO2].capitulos[1].versos[9] = wxT("Pois aquele em quem não há estas coisas é cego, vendo somente o que está perto, havendo-se esquecido da purificação dos seus antigos pecados.");
    b->dados[PEDRO2].capitulos[1].versos[10] = wxT("Portanto, irmãos, procurai mais diligentemente fazer firme a vossa vocação e eleição; porque, fazendo isto, nunca jamais tropeçareis.");
    b->dados[PEDRO2].capitulos[1].versos[11] = wxT("Porque assim vos será amplamente concedida a entrada no reino eterno do nosso Senhor e Salvador Jesus Cristo.");
    b->dados[PEDRO2].capitulos[1].versos[12] = wxT("Pelo que estarei sempre pronto para vos lembrar estas coisas, ainda que as saibais, e estejais confirmados na verdade que já está convosco.");
    b->dados[PEDRO2].capitulos[1].versos[13] = wxT("E tendo por justo, enquanto ainda estou neste tabernáculo, despertar-vos com admoestações,");
    b->dados[PEDRO2].capitulos[1].versos[14] = wxT("sabendo que brevemente hei de deixar este meu tabernáculo, assim como nosso Senhor Jesus Cristo já mo revelou.");
    b->dados[PEDRO2].capitulos[1].versos[15] = wxT("Mas procurarei diligentemente que também em toda ocasião depois da minha morte tenhais lembrança destas coisas.");
    b->dados[PEDRO2].capitulos[1].versos[16] = wxT("Porque não seguimos fábulas engenhosas quando vos fizemos conhecer o poder e a vinda de nosso Senhor Jesus Cristo, pois nós fôramos testemunhas oculares da sua majestade.");
    b->dados[PEDRO2].capitulos[1].versos[17] = wxT("Porquanto ele recebeu de Deus Pai honra e glória, quando pela Glória Magnífica lhe foi dirigida a seguinte voz: Este é o meu Filho amado, em quem me comprazo;");
    b->dados[PEDRO2].capitulos[1].versos[18] = wxT("e essa voz, dirigida do céu, ouvimo-la nós mesmos, estando com ele no monte santo.");
    b->dados[PEDRO2].capitulos[1].versos[19] = wxT("E temos ainda mais firme a palavra profética à qual bem fazeis em estar atentos, como a uma candeia que alumia em lugar escuro, até que o dia amanheça e a estrela da alva surja em vossos corações;");
    b->dados[PEDRO2].capitulos[1].versos[20] = wxT("sabendo primeiramente isto: que nenhuma profecia da Escritura é de particular interpretação.");
    b->dados[PEDRO2].capitulos[1].versos[21] = wxT("Porque a profecia nunca foi produzida por vontade dos homens, mas os homens da parte de Deus falaram movidos pelo Espírito Santo.");

    b->dados[PEDRO2].capitulos[2].versos[1] = wxT("Mas houve também entre o povo falsos profetas, como entre vós haverá falsos mestres, os quais introduzirão encobertamente heresias destruidoras, negando até o Senhor que os resgatou, trazendo sobre si mesmos repentina destruição.");
    b->dados[PEDRO2].capitulos[2].versos[2] = wxT("E muitos seguirão as suas dissoluções, e por causa deles será blasfemado o caminho da verdade;");
    b->dados[PEDRO2].capitulos[2].versos[3] = wxT("também, movidos pela ganância, e com palavras fingidas, eles farão de vós negócio; a condenação dos quais já de largo tempo não tarda e a sua destruição não dormita.");
    b->dados[PEDRO2].capitulos[2].versos[4] = wxT("Porque se Deus não poupou a anjos quando pecaram, mas lançou-os no inferno, e os entregou aos abismos da escuridão, reservando-os para o juízo;");
    b->dados[PEDRO2].capitulos[2].versos[5] = wxT("se não poupou ao mundo antigo, embora preservasse a Noé, pregador da justiça, com mais sete pessoas, ao trazer o dilúvio sobre o mundo dos ímpios;");
    b->dados[PEDRO2].capitulos[2].versos[6] = wxT("se, reduzindo a cinza as cidades de Sodoma e Gomorra, condenou-as à destruição, havendo-as posto para exemplo aos que vivessem impiamente;");
    b->dados[PEDRO2].capitulos[2].versos[7] = wxT("e se livrou ao justo Ló, atribulado pela vida dissoluta daqueles perversos");
    b->dados[PEDRO2].capitulos[2].versos[8] = wxT("{porque este justo, habitando entre eles, por ver e ouvir, afligia todos os dias a sua alma justa com as injustas obras deles};");
    b->dados[PEDRO2].capitulos[2].versos[9] = wxT("também sabe o Senhor livrar da tentação os piedosos, e reservar para o dia do juízo os injustos, que já estão sendo castigados;");
    b->dados[PEDRO2].capitulos[2].versos[10] = wxT("especialmente aqueles que, seguindo a carne, andam em imundas concupiscências, e desprezam toda autoridade. Atrevidos, arrogantes, não receiam blasfemar das dignidades,");
    b->dados[PEDRO2].capitulos[2].versos[11] = wxT("enquanto que os anjos, embora maiores em força e poder, não pronunciam contra eles juízo blasfemo diante do Senhor.");
    b->dados[PEDRO2].capitulos[2].versos[12] = wxT("Mas estes, como criaturas irracionais, por natureza feitas para serem presas e mortas, blasfemando do que não entendem, perecerão na sua corrupção,");
    b->dados[PEDRO2].capitulos[2].versos[13] = wxT("recebendo a paga da sua injustiça; pois que tais homens têm prazer em deleites à luz do dia; nódoas são eles e máculas, deleitando-se em suas dissimulações, quando se banqueteiam convosco;");
    b->dados[PEDRO2].capitulos[2].versos[14] = wxT("tendo os olhos cheios de adultério e insaciáveis no pecar; engodando as almas inconstantes, tendo um coração exercitado na ganância, filhos de maldição;");
    b->dados[PEDRO2].capitulos[2].versos[15] = wxT("os quais, deixando o caminho direito, desviaram-se, tendo seguido o caminho de Balaão, filho de Beor, que amou o prêmio da injustiça,");
    b->dados[PEDRO2].capitulos[2].versos[16] = wxT("mas que foi repreendido pela sua própria transgressão: um mudo jumento, falando com voz humana, impediu a loucura do profeta.");
    b->dados[PEDRO2].capitulos[2].versos[17] = wxT("Estes são fontes sem água, névoas levadas por uma tempestade, para os quais está reservado o negrume das trevas.");
    b->dados[PEDRO2].capitulos[2].versos[18] = wxT("Porque, falando palavras arrogantes de vaidade, nas concupiscências da carne engodam com dissoluções aqueles que mal estão escapando aos que vivem no erro;");
    b->dados[PEDRO2].capitulos[2].versos[19] = wxT("prometendo-lhes liberdade, quando eles mesmos são escravos da corrupção; porque de quem um homem é vencido, do mesmo é feito escravo.");
    b->dados[PEDRO2].capitulos[2].versos[20] = wxT("Porquanto se, depois de terem escapado das corrupções do mundo pelo pleno conhecimento do Senhor e Salvador Jesus Cristo, ficam de novo envolvidos nelas e vencidos, tornou-se-lhes o último estado pior que o primeiro.");
    b->dados[PEDRO2].capitulos[2].versos[21] = wxT("Porque melhor lhes fora não terem conhecido o caminho da justiça, do que, conhecendo-o, desviarem-se do santo mandamento que lhes fora dado.");
    b->dados[PEDRO2].capitulos[2].versos[22] = wxT("Deste modo sobreveio-lhes o que diz este provérbio verdadeiro; Volta o cão ao seu vômito, e a porca lavada volta a revolver-se no lamaçal.");

    b->dados[PEDRO2].capitulos[3].versos[1] = wxT("Amados, já é esta a segunda carta que vos escrevo; em ambas as quais desperto com admoestações o vosso ânimo sincero;");
    b->dados[PEDRO2].capitulos[3].versos[2] = wxT("para que vos lembreis das palavras que dantes foram ditas pelos santos profetas, e do mandamento do Senhor e Salvador, dado mediante os vossos apóstolos;");
    b->dados[PEDRO2].capitulos[3].versos[3] = wxT("sabendo primeiro isto, que nos últimos dias virão escarnecedores com zombaria andando segundo as suas próprias concupiscências,");
    b->dados[PEDRO2].capitulos[3].versos[4] = wxT("e dizendo: Onde está a promessa da sua vinda? porque desde que os pais dormiram, todas as coisas permanecem como desde o princípio da criação.");
    b->dados[PEDRO2].capitulos[3].versos[5] = wxT("Pois eles de propósito ignoram isto, que pela palavra de Deus já desde a antiguidade existiram os céus e a terra, que foi tirada da água e no meio da água subsiste;");
    b->dados[PEDRO2].capitulos[3].versos[6] = wxT("pelas quais coisas pereceu o mundo de então, afogado em água;");
    b->dados[PEDRO2].capitulos[3].versos[7] = wxT("mas os céus e a terra de agora, pela mesma palavra, têm sido guardados para o fogo, sendo reservados para o dia do juízo e da perdição dos homens ímpios.");
    b->dados[PEDRO2].capitulos[3].versos[8] = wxT("Mas vós, amados, não ignoreis uma coisa: que um dia para o Senhor é como mil anos, e mil anos como um dia.");
    b->dados[PEDRO2].capitulos[3].versos[9] = wxT("O Senhor não retarda a sua promessa, ainda que alguns a têm por tardia; porém é longânimo para convosco, não querendo que ninguém se perca, senão que todos venham a arrepender-se.");
    b->dados[PEDRO2].capitulos[3].versos[10] = wxT("Virá, pois, como ladrão o dia do Senhor, no qual os céus passarão com grande estrondo, e os elementos, ardendo, se dissolverão, e a terra, e as obras que nela há, serão descobertas.");
    b->dados[PEDRO2].capitulos[3].versos[11] = wxT("Ora, uma vez que todas estas coisas hão de ser assim dissolvidas, que pessoas não deveis ser em santidade e piedade,");
    b->dados[PEDRO2].capitulos[3].versos[12] = wxT("aguardando, e desejando ardentemente a vinda do dia de Deus, em que os céus, em fogo se dissolverão, e os elementos, ardendo, se fundirão?");
    b->dados[PEDRO2].capitulos[3].versos[13] = wxT("Nós, porém, segundo a sua promessa, aguardamos novos céus e uma nova terra, nos quais habita a justiça.");
    b->dados[PEDRO2].capitulos[3].versos[14] = wxT("Pelo que, amados, como estais aguardando estas coisas, procurai diligentemente que por ele sejais achados imaculados e irrepreensível em paz;");
    b->dados[PEDRO2].capitulos[3].versos[15] = wxT("e tende por salvação a longanimidade de nosso Senhor; como também o nosso amado irmão Paulo vos escreveu, segundo a sabedoria que lhe foi dada;");
    b->dados[PEDRO2].capitulos[3].versos[16] = wxT("como faz também em todas as suas epístolas, nelas falando acerca destas coisas, mas quais há pontos difíceis de entender, que os indoutos e inconstantes torcem, como o fazem também com as outras Escrituras, para sua própria perdição.");
    b->dados[PEDRO2].capitulos[3].versos[17] = wxT("Vós, portanto, amados, sabendo isto de antemão, guardai-vos de que pelo engano dos homens perversos sejais juntamente arrebatados, e descaiais da vossa firmeza;");
    b->dados[PEDRO2].capitulos[3].versos[18] = wxT("antes crescei na graça e no conhecimento de nosso Senhor e Salvador Jesus Cristo. A ele seja dada a glória, assim agora, como até o dia da eternidade.");

}
